const box = document.querySelector('.box');

// We put 'e' in the parameters to catch the Event Object
box.addEventListener('click', function(e) {
  console.log('You clicked exactly here:');
  console.log('X Coordinate:', e.clientX);
  console.log('Y Coordinate:', e.clientY);

  // e.target gives us the EXACT DOM element that was clicked
  console.log('You clicked on:', e.target);
});

document.addEventListener('keydown', function(e) {
  console.log('You pressed the key:', e.key);
});
